-- changeset uakyol:34 dbms:cloudspanner
-- comment: Add entity_key and entity_metadata to EventGroups.

-- Set protobuf FileDescriptorSet as a base64 string. This gets applied to the
-- next DDL batch. Regenerate before merge via:
--   bazel build //src/main/proto/wfa/measurement/internal/kingdom:details_descriptor_set
--   base64 -i bazel-bin/src/main/proto/wfa/measurement/internal/kingdom/details_descriptor_set-transitive-descriptor-set.proto.bin
SET PROTO_DESCRIPTORS = '';

START BATCH DDL;

-- Drop metadata-search columns and search index that depend on
-- `EventGroupDetails`. They block `ALTER PROTO BUNDLE UPDATE` below and are
-- recreated later in this same batch (token values get recomputed from
-- existing EventGroupDetails blobs automatically).
DROP SEARCH INDEX EventGroupsByMetadata;
ALTER TABLE EventGroups DROP COLUMN Metadata_Tokens;
ALTER TABLE EventGroups DROP COLUMN BrandName_Tokens;
ALTER TABLE EventGroups DROP COLUMN CampaignName_Tokens;

-- Register new proto types:
--   * `google.protobuf.Struct` and its transitive dependencies, needed for the
--     new `EventGroupDetails.EventGroupMetadata.entity_metadata` field.
--   * `EventGroupDetails.EntityKey`, the new nested message.
ALTER PROTO BUNDLE INSERT (
  `google.protobuf.Struct`,
  `google.protobuf.Struct.FieldsEntry`,
  `google.protobuf.Value`,
  `google.protobuf.ListValue`,
  `google.protobuf.NullValue`,
  `wfa.measurement.internal.kingdom.EventGroupDetails.EntityKey`,
);

-- Update previously-registered messages that gained fields.
ALTER PROTO BUNDLE UPDATE (
  `wfa.measurement.internal.kingdom.EventGroupDetails`,
  `wfa.measurement.internal.kingdom.EventGroupDetails.EventGroupMetadata`,
);

-- Recreate the metadata-search columns and search index against the updated
-- bundle. Definitions mirror add-event-group-metadata.sql exactly.
ALTER TABLE EventGroups
ADD COLUMN BrandName_Tokens TOKENLIST AS (
  TOKENIZE_FULLTEXT(EventGroupDetails.metadata.ad_metadata.campaign_metadata.brand_name)
) HIDDEN;

ALTER TABLE EventGroups
ADD COLUMN CampaignName_Tokens TOKENLIST AS (
  TOKENIZE_FULLTEXT(EventGroupDetails.metadata.ad_metadata.campaign_metadata.campaign_name)
) HIDDEN;

ALTER TABLE EventGroups
ADD COLUMN Metadata_Tokens TOKENLIST AS (
  TOKENLIST_CONCAT([BrandName_Tokens, CampaignName_Tokens])
) HIDDEN;

CREATE SEARCH INDEX EventGroupsByMetadata ON EventGroups(Metadata_Tokens);

-- STORED generated column for entity_type. Defaults to "campaign" for legacy
-- EventGroups that predate entity_key. NULLIF handles both an unset entity_key
-- message (projection may return NULL) and an explicit empty-string value.
ALTER TABLE EventGroups
ADD COLUMN EntityType STRING(MAX) AS (
  IFNULL(NULLIF(EventGroupDetails.entity_key.entity_type, ""), "campaign")
) STORED;

-- STORED generated column for entity_id. NULL when entity_key is unset, which
-- lets the UNIQUE NULL_FILTERED index below exempt legacy rows.
ALTER TABLE EventGroups
ADD COLUMN EntityId STRING(MAX) AS (
  NULLIF(EventGroupDetails.entity_key.entity_id, "")
) STORED;

-- Supports the entity_type_in filter in ListEventGroups.
CREATE INDEX EventGroupsByEntityType
  ON EventGroups(DataProviderId, MeasurementConsumerId, EntityType);

-- Enforces uniqueness of entity_key per (DataProvider, MeasurementConsumer)
-- as required by cross-media-measurement-api PR #275. NULL_FILTERED skips
-- legacy rows where EntityId is NULL.
CREATE UNIQUE NULL_FILTERED INDEX EventGroupsByEntityKey
  ON EventGroups(DataProviderId, MeasurementConsumerId, EntityType, EntityId);

RUN BATCH;
